use rand::Rng;
use std::iter;
use std::fmt;

const ALPHANUMERIC: &[u8] = b"abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";

fn rand_alphanum(n: usize) -> String {
    (0..n).map(|_| ALPHANUMERIC.choose(&mut rand::thread_rng()).unwrap())
        .take(n)
        .collect()
}

fn generate_api_token() -> String {
    let mut token = String::new();
    for _ in 0..40 {
        token.push(ALPHANUMERIC.choose(&mut rand::thread_rng()).unwrap());
    }
    token
}